  gemma: {
    bg: 'bg-indigo-500',
    text: 'text-white',
    ring: 'ring-indigo-300',
    initial: 'G',
  },
  qwen: {
    bg: 'bg-sky-500',
    text: 'text-white',
    ring: 'ring-sky-300',
    initial: 'Q',
